-- Mevcut tarih ve zaman
SELECT NOW() AS current_datetime;
SELECT CURDATE() AS today;
SELECT CURTIME() AS current_time;

-- Tarihten yil, ay, gun cikarma
SELECT
    created_at,
    YEAR(created_at) AS year,
    MONTH(created_at) AS month,
    DAY(created_at) AS day
FROM students;

-- Tarih farki hesaplama
SELECT
    name,
    created_at,
    DATEDIFF(NOW(), created_at) AS days_since_registration
FROM students;

-- Tarihe gun/ay/yil ekleme
SELECT DATE_ADD(CURDATE(), INTERVAL 30 DAY) AS thirty_days_later;
SELECT DATE_ADD(CURDATE(), INTERVAL 1 YEAR) AS one_year_later;

-- Tarih formatlama
SELECT DATE_FORMAT(NOW(), '%d-%m-%Y') AS formatted_date;
SELECT DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s') AS full_datetime;

-- Son 7 gunde kayit olanlar
SELECT name, created_at
FROM students
WHERE created_at >= DATE_SUB(NOW(), INTERVAL 7 DAY);
